import type { CareerQuestion } from "./rrt-questions";

export const otaQuestionsBatch12: CareerQuestion[] = [
  { id: "ota-2103", stem: "An OTA is treating a client with lateral epicondylitis. Which activity modification is MOST important?", options: ["Avoid all arm use", "Use a counterforce brace and modify grip activities to reduce wrist extensor strain", "Only perform isometric exercises", "Apply ice continuously"], correctIndex: 1, rationale: "Lateral epicondylitis management includes counterforce bracing to redistribute forces, ergonomic modifications to reduce wrist extensor strain, and graded strengthening after acute inflammation subsides.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-2104", stem: "A client with Parkinson's disease has micrographia. Which strategy helps improve handwriting?", options: ["Write faster", "Use lined paper with visual cues, larger writing instruments, and external auditory cues to increase letter size", "Switch to dominant hand", "Avoid writing entirely"], correctIndex: 1, rationale: "Parkinson's micrographia is treated with external cues: lined paper, visual targets for letter size, auditory pacing, larger grip writing tools, and conscious effort to write larger. External cues bypass basal ganglia dysfunction.", difficulty: 2, category: "Neurological Rehabilitation", topic: "Neurological Rehab" },
  { id: "ota-2105", stem: "An OTA is evaluating a child's visual-motor integration. Which standardized assessment is commonly used?", options: ["Manual muscle testing", "Beery-Buktenica Developmental Test of Visual-Motor Integration (Beery VMI)", "Functional Independence Measure", "Allen Cognitive Level Screen"], correctIndex: 1, rationale: "The Beery VMI is a widely used standardized assessment of visual-motor integration for children ages 2-100. It involves copying geometric forms of increasing complexity and has supplemental visual perception and motor coordination subtests.", difficulty: 1, category: "Pediatric Rehabilitation", topic: "Pediatric OT" },
  { id: "ota-2106", stem: "A client with COPD becomes dyspneic during grooming activities. Which energy conservation technique is MOST helpful?", options: ["Complete all grooming at once", "Sit during grooming, use pursed-lip breathing, organize supplies within reach, and take rest breaks between tasks", "Skip grooming activities", "Only groom every other day"], correctIndex: 1, rationale: "COPD energy conservation during grooming: sit rather than stand, organize supplies at waist height, use pursed-lip breathing during exertion, rest between steps, use long-handled tools, and pace the activity.", difficulty: 1, category: "Clinical Scenarios", topic: "Rehabilitation Principles" },
  { id: "ota-2107", stem: "An OTA is providing constraint-induced movement therapy (CIMT). What is the key principle?", options: ["Constrain both hands", "Restrain the unaffected upper extremity to force intensive use of the affected limb for functional tasks", "Only passive range of motion", "Bilateral training exclusively"], correctIndex: 1, rationale: "CIMT constrains the unaffected UE (mitt/sling) while intensively training the affected UE for 6+ hours/day for 2-3 weeks. It overcomes learned nonuse and promotes cortical reorganization through massed practice.", difficulty: 3, category: "Neurological Rehabilitation", topic: "Neurological Rehab" },
  { id: "ota-2108", stem: "A client with a rotator cuff repair is 6 weeks post-surgery. What phase of rehabilitation is typically initiated?", options: ["Aggressive strengthening", "Active-assisted ROM progressing to active ROM within pain-free limits as tissue healing permits", "Return to full activity", "No movement until 12 weeks"], correctIndex: 1, rationale: "At 6 weeks post-rotator cuff repair, AAROM progresses to AROM as healing permits. Passive ROM was done in weeks 0-6. Strengthening typically begins at 8-12 weeks depending on tear size and surgeon protocol.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-2109", stem: "An OTA observes a child using a palmar supinate grasp at age 5. What does this indicate?", options: ["Age-appropriate development", "A developmental delay in fine motor grasp pattern — by age 5, a dynamic tripod grasp should be emerging", "Superior motor control", "No intervention needed"], correctIndex: 1, rationale: "Palmar supinate grasp is typical at 1-1.5 years. By age 5, children should demonstrate a static or dynamic tripod grasp. A palmar supinate grasp at age 5 indicates fine motor developmental delay requiring OT intervention.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "Pediatric OT" },
  { id: "ota-2110", stem: "A client with diabetes is receiving hand therapy. What precaution is essential regarding modalities?", options: ["No precautions needed", "Monitor for decreased sensation (neuropathy) and avoid thermal modalities on insensate areas to prevent burns", "Use maximum heat settings", "Only use cryotherapy"], correctIndex: 1, rationale: "Diabetic neuropathy reduces protective sensation. Thermal modalities (paraffin, hot packs, ultrasound) can cause burns in insensate areas. Always test sensation before applying thermal agents and monitor skin closely.", difficulty: 2, category: "Patient Safety", topic: "Rehabilitation Principles" },
  { id: "ota-2111", stem: "An OTA is teaching a client with hemiplegia to don a button-down shirt. What technique is correct?", options: ["Put the unaffected arm in first", "Place the affected arm into the sleeve first, then drape the shirt behind and insert the unaffected arm", "Always use pullover shirts instead", "Have someone else dress the client"], correctIndex: 1, rationale: "Hemiplegic dressing: affected arm goes in first for donning (to position the sleeve while the unaffected hand is free to assist). For doffing, the unaffected arm comes out first. Mnemonic: 'affected first on, last off.'", difficulty: 1, category: "Clinical Case Scenarios", topic: "ADL Training" },
  { id: "ota-2112", stem: "A client with a median nerve laceration at the wrist has difficulty with thumb opposition. Which functional activity is MOST affected?", options: ["Wrist extension", "Precision pinch activities such as picking up small objects, buttoning, and writing", "Shoulder flexion", "Elbow extension"], correctIndex: 1, rationale: "Median nerve at wrist affects thenar muscles (opponens pollicis, abductor pollicis brevis, flexor pollicis brevis). Loss of opposition eliminates precision pinch needed for buttons, coins, writing, and fine manipulation.", difficulty: 2, category: "Anatomy & Physiology", topic: "Hand Therapy" },
  { id: "ota-2113", stem: "An OTA is working in an acute inpatient rehabilitation facility. What is the minimum therapy requirement for patients?", options: ["30 minutes per day", "3 hours of therapy per day, at least 5 days per week, with at least 2 therapy disciplines", "1 hour per week", "No minimum requirement exists"], correctIndex: 1, rationale: "Acute inpatient rehabilitation requires a minimum of 3 hours of therapy per day, 5 days per week, from at least 2 disciplines (PT, OT, SLP). This '3-hour rule' is a CMS requirement for admission.", difficulty: 1, category: "Rehabilitation Planning", topic: "Rehabilitation Principles" },
  { id: "ota-2114", stem: "A client with a traumatic brain injury at Rancho Level IV demonstrates which behavioral characteristics?", options: ["Purposeful and appropriate behavior", "Confused-agitated behavior with heightened state of activity, bizarre behavior, and inability to cooperate with treatment", "Comatose and unresponsive", "Independent in all activities"], correctIndex: 1, rationale: "Rancho Level IV (Confused-Agitated): heightened activity, severely decreased ability to process information, bizarre/agitated behavior, short attention span, no short-term memory, and may be combative or inappropriate.", difficulty: 2, category: "Neurological Rehabilitation", topic: "Cognitive Rehab" },
  { id: "ota-2115", stem: "An OTA is fabricating a dynamic MCP extension splint. What is the purpose?", options: ["Prevent all finger motion", "Apply low-load prolonged stress to increase MCP extension in joints with flexion contractures", "Immobilize the wrist", "Strengthen grip"], correctIndex: 1, rationale: "Dynamic MCP extension splinting applies low-load prolonged stress (LLPS) to tissues shortened by MCP flexion contractures. The dynamic component provides constant gentle force to gradually increase extension ROM over time.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Splinting" },
  { id: "ota-2116", stem: "A client in a mental health setting reports hearing voices telling them to harm themselves. What is the OTA's FIRST action?", options: ["Continue the treatment session", "Ensure client safety, report command auditory hallucinations to the supervising OTR and treatment team immediately", "Ignore the disclosure", "Discharge the client from OT"], correctIndex: 1, rationale: "Command auditory hallucinations directing self-harm are a psychiatric emergency. The OTA must ensure immediate safety, report to the supervising OTR and treatment team, document the disclosure, and follow facility safety protocols.", difficulty: 2, category: "Patient Safety", topic: "Mental Health OT" },
  { id: "ota-2117", stem: "An OTA is assessing a client's functional cognition during meal preparation. Which cognitive skill is required for following a new recipe?", options: ["Only motor skills", "Attention, sequencing, working memory, reading comprehension, problem-solving, and time management", "Only visual skills", "Only language skills"], correctIndex: 1, rationale: "Recipe following requires multiple cognitive domains: sustained attention (following steps), sequencing (correct order), working memory (holding instructions), reading comprehension, problem-solving (substitutions), and time management (timing multiple items).", difficulty: 1, category: "Clinical Case Scenarios", topic: "Cognitive Rehab" },
  { id: "ota-2118", stem: "A client with rheumatoid arthritis has swan neck deformity. Which finger position is characteristic?", options: ["DIP hyperextension, PIP flexion", "PIP hyperextension and DIP flexion due to volar plate laxity and lateral band displacement", "MCP ulnar deviation only", "Mallet finger position"], correctIndex: 1, rationale: "Swan neck deformity: PIP hyperextension + DIP flexion. Caused by volar plate laxity at PIP, dorsal displacement of lateral bands, and FDP pull causing DIP flexion. Impairs functional grip and pinch.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2119", stem: "An OTA is providing caregiver training for a client with dysphagia. What safety instruction is essential?", options: ["Feed the client while lying flat", "Position the client upright at 90° during meals, use thickened liquids as prescribed, and keep the client upright for 30 minutes after eating", "Allow the client to eat independently without monitoring", "Only provide thin liquids"], correctIndex: 1, rationale: "Dysphagia safety: upright 90° positioning, follow speech therapist's diet recommendations (thickened liquids, modified textures), supervise meals, remain upright 30 minutes post-meal, and recognize signs of aspiration.", difficulty: 1, category: "Patient Education", topic: "ADL Training" },
  { id: "ota-2120", stem: "A client with a peripheral nerve injury demonstrates a claw hand deformity. Which nerve is MOST likely affected?", options: ["Median nerve", "Ulnar nerve causing intrinsic minus position with MCP hyperextension and IP flexion in the ring and small fingers", "Radial nerve", "Musculocutaneous nerve"], correctIndex: 1, rationale: "Ulnar nerve palsy causes claw hand: MCP hyperextension (loss of lumbricals/interossei) and IP flexion (unopposed extrinsic flexors) in the ring and small fingers. The 'ulnar claw' is more pronounced in low ulnar nerve lesions.", difficulty: 3, category: "Anatomy & Physiology", topic: "Hand Therapy" },
  { id: "ota-2121", stem: "An OTA is planning a group session for clients with social anxiety. Which group format is MOST appropriate initially?", options: ["Large open discussion group", "Structured parallel group with individual tasks performed alongside others to build comfort with social presence", "Competitive game group", "Unstructured free time"], correctIndex: 1, rationale: "For social anxiety, start with parallel groups (individual tasks alongside others) to build comfort with social presence. Progress gradually to project groups, cooperative groups, then egocentric-cooperative groups as anxiety decreases.", difficulty: 2, category: "Clinical Case Scenarios", topic: "Mental Health OT" },
  { id: "ota-2122", stem: "A client with a hip fracture fixation is on anticoagulant therapy. What precaution should the OTA observe during treatment?", options: ["No precautions needed", "Monitor for signs of excessive bleeding, bruising, and avoid aggressive soft tissue mobilization that could cause hemorrhage", "Apply vigorous massage", "Ignore medication status"], correctIndex: 1, rationale: "Anticoagulant precautions: monitor for excessive bruising/bleeding, avoid aggressive soft tissue techniques, watch for signs of internal bleeding (sudden pain, swelling), and coordinate with nursing regarding INR levels.", difficulty: 2, category: "Patient Safety", topic: "Rehabilitation Principles" },
  { id: "ota-2123", stem: "An OTA is treating a child with cerebral palsy who has spastic diplegia. Which positioning strategy facilitates feeding?", options: ["Reclined position", "Seated upright with hips, knees, and ankles at 90° with trunk support and feet flat for stability", "Prone position", "Standing frame during meals"], correctIndex: 1, rationale: "Spastic diplegia feeding position: seated upright, hips/knees/ankles at 90°, trunk support as needed, feet flat on a surface, head midline in slight chin tuck, and arms supported. This position inhibits extensor tone and facilitates oral motor control.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "Pediatric OT" },
  { id: "ota-2124", stem: "A client with carpal tunnel syndrome reports nighttime paresthesias. Which splint position is recommended for sleeping?", options: ["Full wrist flexion", "Wrist in neutral position to minimize pressure on the median nerve within the carpal tunnel", "Full wrist extension", "Thumb spica position"], correctIndex: 1, rationale: "Carpal tunnel nighttime splinting: wrist neutral (0° extension) minimizes carpal tunnel pressure. Flexion and extension both increase tunnel pressure. Worn at night because wrists often flex during sleep, compressing the median nerve.", difficulty: 1, category: "Orthopedic Rehabilitation", topic: "Splinting" },
  { id: "ota-2125", stem: "An OTA is documenting a treatment note using the SOAP format. What belongs in the Assessment section?", options: ["Client's vital signs", "Clinical interpretation of data, progress toward goals, treatment effectiveness, and justification for continued services", "The treatment activities performed", "The client's subjective complaints"], correctIndex: 1, rationale: "SOAP Assessment section: clinical reasoning, interpretation of objective findings, progress toward goals, barriers to progress, treatment effectiveness, and professional judgment supporting the plan for continued or modified services.", difficulty: 1, category: "Documentation", topic: "Rehabilitation Principles" },
  { id: "ota-2126", stem: "A client with multiple sclerosis reports increased fatigue in the afternoon. What scheduling modification should the OTA recommend?", options: ["Schedule all activities in the afternoon", "Perform the most demanding activities in the morning when energy is highest and use energy conservation throughout the day", "Eliminate all afternoon activities", "Push through the fatigue"], correctIndex: 1, rationale: "MS fatigue management: schedule demanding tasks during peak energy (typically morning), use energy conservation principles, take planned rest breaks, maintain cool environment, pace activities, and prioritize essential tasks.", difficulty: 1, category: "Neurological Rehabilitation", topic: "Rehabilitation Principles" },
  { id: "ota-2127", stem: "An OTA is treating a burn client in the acute phase. What is the PRIMARY goal of splinting?", options: ["Increase strength", "Position joints in anti-deformity positions to prevent contracture formation during wound healing", "Allow maximum movement", "Apply compression"], correctIndex: 1, rationale: "Acute burn splinting: anti-deformity positioning to oppose the contracture forces of scar tissue. Common positions: neck extension, shoulder abduction/ER, elbow extension, wrist extension, MCP flexion, thumb abduction.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "Splinting" },
  { id: "ota-2128", stem: "A client with Alzheimer's disease is in the moderate stage. Which activity is MOST appropriate?", options: ["Complex multi-step cooking", "Familiar repetitive activities such as folding towels, sorting objects, or simple gardening with cueing", "Abstract reasoning tasks", "Learning new computer skills"], correctIndex: 1, rationale: "Moderate Alzheimer's: familiar, repetitive, success-oriented activities that tap procedural (automatic) memory. Folding, sorting, and simple gardening provide meaningful engagement without excessive cognitive demand.", difficulty: 1, category: "Geriatric Rehabilitation", topic: "Cognitive Rehab" },
  { id: "ota-2129", stem: "An OTA is performing a job site analysis for a client returning to work as a cashier after a wrist injury. What ergonomic factors should be assessed?", options: ["Only the client's strength", "Workstation height, repetitive motion demands, force requirements, posture, rest breaks, and potential for adaptive equipment", "Only the commute distance", "Only the work schedule"], correctIndex: 1, rationale: "Job site analysis for cashier: workstation height, scanning/bagging repetitive demands, force for handling products, standing vs. sitting options, wrist positioning, anti-fatigue mats, rest break schedule, and adaptive equipment needs.", difficulty: 2, category: "Rehabilitation Planning", topic: "Rehabilitation Principles" },
  { id: "ota-2130", stem: "A client with a brachial plexus injury affecting C8-T1 (Klumpke's palsy) has which functional deficit?", options: ["Shoulder abduction loss", "Loss of hand intrinsic function with claw hand deformity and impaired grip and fine motor control", "Elbow flexion loss", "Wrist extension loss"], correctIndex: 1, rationale: "Klumpke's palsy (C8-T1): loss of hand intrinsics (lumbricals, interossei), finger flexors, and wrist flexors. Results in claw hand deformity, impaired grip/pinch, and loss of fine motor dexterity. Shoulder and elbow preserved.", difficulty: 3, category: "Anatomy & Physiology", topic: "Neurological Rehab" },
  { id: "ota-2131", stem: "An OTA is providing home modification recommendations for a client with low vision. Which adaptation is MOST important for safety?", options: ["Remove all furniture", "Increase lighting, add color contrast at transitions (stairs, thresholds), and remove tripping hazards", "Paint all walls white", "Install motion-sensor alarms"], correctIndex: 1, rationale: "Low vision home safety: increased lighting (especially task lighting), high-contrast color markings at stairs/thresholds/edges, remove throw rugs/clutter, tactile markers on appliances, and consistent furniture placement.", difficulty: 1, category: "Geriatric Rehabilitation", topic: "Assistive Devices" },
  { id: "ota-2132", stem: "A client with a total knee replacement is 3 days post-surgery. What functional activity should the OTA address?", options: ["Running", "Bed mobility, transfers, basic ADLs, and beginning to practice stair negotiation with appropriate assistive device", "Return to sports", "Heavy lifting"], correctIndex: 1, rationale: "Post-TKR day 3: focus on bed mobility, sit-to-stand transfers, basic ADLs (bathing, dressing with adaptive equipment), and assisted ambulation. OT addresses UE-assisted transfers and ADL independence with precautions.", difficulty: 1, category: "Clinical Scenarios", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-2133", stem: "An OTA is using the Canadian Occupational Performance Measure (COPM) with a client. What does this assessment evaluate?", options: ["Physical strength only", "The client's self-perception of occupational performance and satisfaction in self-care, productivity, and leisure", "Cognitive function only", "Range of motion"], correctIndex: 1, rationale: "The COPM is a client-centered, semi-structured interview that measures self-perceived occupational performance and satisfaction across self-care, productivity, and leisure. Clients rate importance, performance, and satisfaction on 1-10 scales.", difficulty: 2, category: "Clinical Scenarios", topic: "Rehabilitation Principles" },
  { id: "ota-2134", stem: "A client with cubital tunnel syndrome has ulnar nerve compression at the elbow. Which sleeping position should be avoided?", options: ["Sleeping supine", "Sleeping with the elbow fully flexed, which increases pressure on the ulnar nerve in the cubital tunnel", "Sleeping with arms at sides", "Sleeping prone"], correctIndex: 1, rationale: "Cubital tunnel syndrome: elbow flexion increases pressure on the ulnar nerve. Nocturnal splinting in 30-45° elbow extension, avoid prolonged flexion, elbow pad to reduce direct pressure, and nerve gliding exercises.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2135", stem: "An OTA is working with a client who has bilateral upper extremity amputations. What is the priority for prosthetic training?", options: ["Cosmetic appearance only", "Functional independence in ADLs including feeding, hygiene, and dressing using body-powered or myoelectric prostheses", "Only recreational activities", "Only vocational tasks"], correctIndex: 1, rationale: "Bilateral UE amputation prosthetic training: prioritize ADL independence (feeding, hygiene, toileting, dressing). Train controls, grasp/release, prehension patterns, and bilateral coordination. Usually dominant side fitted first.", difficulty: 3, category: "Clinical Case Scenarios", topic: "Assistive Devices" },
  { id: "ota-2136", stem: "A client with a CVA has left neglect. Which compensatory strategy should the OTA teach?", options: ["Ignore the left side", "Anchoring — place a bright colored line on the left margin of reading material and teach systematic left-to-right visual scanning", "Only work on the right side", "Cover the right visual field"], correctIndex: 1, rationale: "Left neglect compensatory strategies: anchoring (bright marker on left margin), systematic scanning left to right, placing important items on affected side, lighthouse strategy, and environmental cues on the neglected side.", difficulty: 2, category: "Neurological Rehabilitation", topic: "Cognitive Rehab" },
  { id: "ota-2137", stem: "An OTA is evaluating hand edema using volumetric measurement. What is the standard method?", options: ["Estimate by visual inspection", "Submerge the hand in a volumeter filled to the overflow spout and measure the displaced water in a graduated cylinder", "Measure circumference with a tape", "Weigh the hand on a scale"], correctIndex: 1, rationale: "Volumetric measurement: hand submerged in volumeter (water displacement method) with water collected in graduated cylinder. Most accurate and reliable method for whole-hand edema measurement. Compare to contralateral hand.", difficulty: 1, category: "Clinical Scenarios", topic: "Rehabilitation Principles" },
  { id: "ota-2138", stem: "A client with chronic pain is catastrophizing about their condition. Which cognitive-behavioral approach is appropriate?", options: ["Agree with catastrophic thoughts", "Cognitive restructuring to identify and challenge negative automatic thoughts and replace them with more realistic appraisals", "Avoid discussing pain", "Only use physical modalities"], correctIndex: 1, rationale: "Pain catastrophizing treatment: cognitive restructuring (identify distorted thoughts, examine evidence, develop alternative thoughts), graded activity exposure, relaxation training, pain neuroscience education, and self-efficacy building.", difficulty: 3, category: "Clinical Case Scenarios", topic: "Rehabilitation Principles" },
  { id: "ota-2139", stem: "An OTA is working with a client who has post-polio syndrome. Which exercise principle is essential?", options: ["High-intensity strengthening", "Non-fatiguing exercise with adequate rest — overwork weakness can worsen post-polio symptoms", "Push through fatigue", "Marathon training approach"], correctIndex: 1, rationale: "Post-polio syndrome: avoid overwork weakness (exercising to fatigue can damage remaining motor neurons). Use non-fatiguing exercise, pacing, energy conservation, appropriate assistive devices, and monitor for delayed weakness.", difficulty: 3, category: "Neurological Rehabilitation", topic: "Rehabilitation Principles" },
  { id: "ota-2140", stem: "A client recovering from Guillain-Barré syndrome is in the recovery phase. What type of exercise progression is appropriate?", options: ["Immediate heavy resistance", "Gentle active ROM progressing to light resistive exercises as nerve regeneration occurs, monitoring for overwork weakness", "No exercise until fully recovered", "Only passive stretching"], correctIndex: 1, rationale: "GBS recovery: gentle AROM as strength returns, progress to light resistance gradually, monitor for overwork weakness, use functional activities, address fatigue with pacing, and adapt exercises to the pattern of nerve recovery.", difficulty: 3, category: "Neurological Rehabilitation", topic: "Neurological Rehab" },
  { id: "ota-2141", stem: "An OTA is treating a client with complex regional pain syndrome (CRPS) Type I. Which treatment approach is indicated?", options: ["Aggressive passive stretching", "Stress loading program (scrubbing and carrying activities), desensitization, mirror therapy, and graded motor imagery", "Complete immobilization", "Only hot packs"], correctIndex: 1, rationale: "CRPS Type I treatment: stress loading (scrubbing/carrying — provides compression and distraction without painful joint motion), desensitization, mirror therapy, graded motor imagery, gentle AROM, and edema management.", difficulty: 4, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2142", stem: "A client with an intellectual disability is learning to use public transportation. Which teaching strategy is MOST effective?", options: ["Verbal instructions only", "Task analysis with systematic instruction, visual supports, in-vivo practice on actual routes, and gradual fading of prompts", "Written manual", "Classroom lecture"], correctIndex: 1, rationale: "Community skill training for intellectual disability: task analysis, systematic instruction (forward/backward chaining), visual supports (picture schedules), in-vivo practice on actual routes, natural cues, and systematic prompt fading.", difficulty: 2, category: "Rehabilitation Planning", topic: "ADL Training" },
  { id: "ota-2143", stem: "An OTA is using sensory integration therapy with a child who is gravitationally insecure. Which activity should be introduced FIRST?", options: ["High-speed spinning", "Slow linear vestibular input on stable equipment close to the ground with the child in control of the movement", "Inverted hanging", "Rapid direction changes"], correctIndex: 1, rationale: "Gravitational insecurity: start with slow, linear vestibular input (swinging back and forth) on low equipment, child controls speed/direction, provide proprioceptive input concurrently, and gradually increase intensity as tolerance improves.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "Sensory Processing" },
  { id: "ota-2144", stem: "A client with COPD is using pursed-lip breathing during functional activities. What is the physiological benefit?", options: ["Increases respiratory rate", "Creates back-pressure that keeps airways open longer, prevents air trapping, and improves oxygen/carbon dioxide exchange", "Strengthens vocal cords", "Reduces need for supplemental oxygen completely"], correctIndex: 1, rationale: "Pursed-lip breathing: creates positive back-pressure during exhalation, prevents premature airway collapse, reduces air trapping, prolongs expiration, improves gas exchange, and reduces dyspnea during activities.", difficulty: 2, category: "Clinical Scenarios", topic: "Rehabilitation Principles" },
  { id: "ota-2145", stem: "An OTA is performing manual edema mobilization (MEM) on a client's hand. What technique is used?", options: ["Deep tissue massage", "Light-pressure massage that follows lymphatic pathways, starting proximally and working distally to promote fluid reabsorption", "Joint mobilization", "Trigger point therapy"], correctIndex: 1, rationale: "Manual edema mobilization: light-pressure lymphatic massage, start proximally (clear trunk/axilla first), then work distally. Stimulates lymphatic contraction, follows lymphatic anatomy, and combines with elevation and compression.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2146", stem: "A client with a spinal cord injury at T6 develops sudden severe headache, sweating above the injury level, and blood pressure spike. What condition should the OTA suspect?", options: ["Migraine headache", "Autonomic dysreflexia — a medical emergency requiring immediate identification and removal of the noxious stimulus below the injury level", "Common cold", "Anxiety attack"], correctIndex: 1, rationale: "Autonomic dysreflexia (SCI at T6 or above): triggered by noxious stimulus below injury (full bladder, constipation, skin irritation). Symptoms: severe HTN, headache, sweating/flushing above lesion, bradycardia. Emergency: sit up, find/remove stimulus, call for help.", difficulty: 2, category: "Patient Safety", topic: "Neurological Rehab" },
  { id: "ota-2147", stem: "An OTA is treating a client with trigger finger. Which conservative intervention is appropriate?", options: ["Aggressive stretching of the finger", "Blocking splint to prevent MCP flexion, tendon gliding exercises, and activity modification to reduce repetitive gripping", "Only surgical referral", "Ignore symptoms"], correctIndex: 1, rationale: "Trigger finger conservative treatment: MCP extension blocking splint (limits flexion to reduce A1 pulley irritation), tendon gliding exercises, activity modification, ergonomic changes, and corticosteroid injection as needed.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2148", stem: "A client with autism spectrum disorder has difficulty with transitions between activities. Which strategy is MOST effective?", options: ["Abrupt transitions without warning", "Visual schedule with countdown timer, verbal previews, transition objects, and consistent routines", "Only verbal warnings", "Eliminate all transitions"], correctIndex: 1, rationale: "ASD transition strategies: visual schedules, countdown timers (5-minute warning), verbal/visual previews of next activity, transition objects, first-then boards, consistent routines, and social stories about transitions.", difficulty: 1, category: "Pediatric Rehabilitation", topic: "Pediatric OT" },
  { id: "ota-2149", stem: "An OTA is evaluating a client's grip strength. What is the standard testing position for dynamometer assessment?", options: ["Lying supine with arm overhead", "Seated, shoulder adducted, elbow flexed 90°, forearm neutral, with the dynamometer handle in the second position", "Standing with arm fully extended", "Any comfortable position"], correctIndex: 1, rationale: "Standard grip strength position (ASHT): seated, shoulder adducted and neutrally rotated, elbow at 90° flexion, forearm neutral, wrist 0-30° extension. Dynamometer handle position 2. Three trials, average or best score recorded.", difficulty: 1, category: "Clinical Scenarios", topic: "Rehabilitation Principles" },
  { id: "ota-2150", stem: "A client with a brain tumor affecting the right parietal lobe demonstrates which perceptual deficit?", options: ["Aphasia", "Left-sided unilateral neglect, impaired spatial orientation, and constructional apraxia", "Right homonymous hemianopsia", "Auditory processing disorder"], correctIndex: 1, rationale: "Right parietal lobe lesion: left unilateral neglect, spatial disorientation, constructional apraxia (difficulty assembling/drawing/building), body scheme disorders, and impaired figure-ground perception. Different from occipital visual field deficits.", difficulty: 3, category: "Neurological Rehabilitation", topic: "Cognitive Rehab" },
  { id: "ota-2151", stem: "An OTA is providing feeding therapy to an infant with poor oral motor control. What positioning is critical?", options: ["Reclined with head extended", "Supported upright with head in midline, slight chin tuck, and trunk stability to facilitate safe swallowing", "Side-lying without support", "Prone position"], correctIndex: 1, rationale: "Infant feeding positioning: supported upright, head midline with slight chin tuck, trunk stability, hips flexed. This position reduces aspiration risk, facilitates lip closure, tongue control, and organized sucking-swallowing-breathing coordination.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "Pediatric OT" },
  { id: "ota-2152", stem: "A client with a hip precaution (posterior approach) needs to pick up an object from the floor. What adaptive technique should the OTA teach?", options: ["Bend at the waist", "Use a reacher or perform a golfer's reach (extend the operated leg behind while leaning forward with support)", "Squat down", "Kneel on both knees"], correctIndex: 1, rationale: "Post-THR posterior approach floor pickup: use a long-handled reacher, or golfer's reach (extend operated leg behind, lean forward with support from stable surface). Prevents hip flexion beyond 90°.", difficulty: 1, category: "Clinical Case Scenarios", topic: "ADL Training" },
  { id: "ota-2153", stem: "An OTA is treating a client with ulnar nerve entrapment. Which Froment's sign indicates ulnar nerve dysfunction?", options: ["Wrist drop during grip", "Flexion of the thumb IP joint during lateral pinch due to compensatory FPL use for weak adductor pollicis", "Inability to extend the thumb", "Loss of wrist extension"], correctIndex: 1, rationale: "Froment's sign: when performing lateral (key) pinch, the thumb IP joint flexes because the adductor pollicis (ulnar nerve) is weak, so the FPL (median nerve) compensates. Positive Froment's = ulnar nerve dysfunction.", difficulty: 4, category: "Anatomy & Physiology", topic: "Hand Therapy" },
  { id: "ota-2154", stem: "A client with depression in a psychiatric setting has decreased motivation for self-care. Which approach is MOST therapeutic?", options: ["Force compliance with schedule", "Grade activities from simple to complex, provide choices, set achievable daily goals, and use positive reinforcement", "Wait for medication to work", "Only discuss feelings"], correctIndex: 1, rationale: "Depression self-care approach: grade activities (start simple), offer choices (autonomy), set achievable goals (success experiences), positive reinforcement, establish routine, and address cognitive distortions about capability.", difficulty: 2, category: "Clinical Case Scenarios", topic: "Mental Health OT" },
  { id: "ota-2155", stem: "An OTA is applying a figure-of-eight wrap for edema control of the hand. In which direction should wrapping proceed?", options: ["Proximal to distal only", "Distal to proximal, starting at the fingertips and progressing toward the wrist to move fluid centrally", "Random direction", "Circumferential at the wrist only"], correctIndex: 1, rationale: "Edema wrapping: always distal to proximal to push excess fluid centrally toward lymphatic drainage. Figure-of-eight pattern distributes pressure evenly. Apply moderate compression — too tight restricts circulation.", difficulty: 1, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2156", stem: "A client with an above-knee amputation is learning to transfer. Which direction should the transfer be performed?", options: ["Always toward the amputated side", "Transfer toward the intact (sound) limb side to provide stable weight-bearing during the transfer", "Direction doesn't matter", "Only with a mechanical lift"], correctIndex: 1, rationale: "AKA transfers: transfer toward the intact limb side (sound leg provides stable weight-bearing). Lead with the intact leg, stand on intact leg, pivot, and sit. Use armrests and ensure wheelchair is locked.", difficulty: 2, category: "Clinical Case Scenarios", topic: "ADL Training" },
  { id: "ota-2157", stem: "An OTA observes that a client's wound has yellow, stringy tissue in the wound bed. What type of tissue is this?", options: ["Granulation tissue", "Slough — devitalized tissue that needs to be debrided for wound healing to progress", "Epithelial tissue", "Healthy muscle tissue"], correctIndex: 1, rationale: "Slough: yellow, stringy, or mucinous devitalized tissue. Must be removed for healing. Debridement methods: autolytic (moisture retentive dressings), enzymatic (collagenase), sharp (physician), or mechanical. Different from eschar (black/brown hard tissue).", difficulty: 2, category: "Patient Safety", topic: "Rehabilitation Principles" },
  { id: "ota-2158", stem: "A client with a C4 spinal cord injury needs environmental control. What technology is MOST appropriate?", options: ["Standard light switches", "Voice-activated or sip-and-puff environmental control unit to operate lights, phone, TV, and other devices", "Standard remote controls", "Manual switches"], correctIndex: 1, rationale: "C4 SCI: no upper extremity function. Environmental control via voice activation, sip-and-puff, head/chin switches, or eye-gaze systems. Can control lights, TV, phone, door locks, thermostat, and emergency call systems.", difficulty: 2, category: "Assistive Devices", topic: "Assistive Devices" },
  { id: "ota-2159", stem: "An OTA is leading a stress management group. Which relaxation technique involves systematically tensing and releasing muscle groups?", options: ["Guided imagery", "Progressive muscle relaxation (PMR) — sequentially tensing and relaxing major muscle groups to reduce physical tension", "Mindfulness meditation", "Diaphragmatic breathing"], correctIndex: 1, rationale: "Progressive muscle relaxation (Jacobson): systematically tense (5-7 seconds) then release (20-30 seconds) each muscle group. Teaches discrimination between tension and relaxation. Typically 16 muscle groups, later condensed to 4-7.", difficulty: 1, category: "Clinical Case Scenarios", topic: "Mental Health OT" },
  { id: "ota-2160", stem: "A client with myasthenia gravis is being treated by the OTA. When during the day should therapy be scheduled?", options: ["End of the day", "Early morning or shortly after medication (anticholinesterase) when muscle strength is optimal", "During peak fatigue", "Midnight"], correctIndex: 1, rationale: "Myasthenia gravis: fatigable weakness worsens throughout the day and with activity. Schedule therapy in the morning or shortly after anticholinesterase medication (peak effect ~1 hour post-dose) when strength is greatest.", difficulty: 2, category: "Neurological Rehabilitation", topic: "Rehabilitation Principles" },
  { id: "ota-2161", stem: "An OTA is assessing a child's handedness. At what age is hand dominance typically established?", options: ["6 months", "By age 5-6 years, though hand preference often emerges between 2-4 years", "12 months", "10 years"], correctIndex: 1, rationale: "Hand dominance: preference emerges 2-4 years, established by 5-6 years. Before age 2, bilateral hand use is normal. Consistent hand preference before 12-18 months may indicate contralateral neurological involvement.", difficulty: 1, category: "Pediatric Rehabilitation", topic: "Pediatric OT" },
  { id: "ota-2162", stem: "A client with a radial nerve palsy has wrist drop. Which splint is indicated?", options: ["Resting hand splint", "Dynamic wrist extension splint or static wrist cock-up splint to support the wrist in extension for functional hand use", "Thumb spica splint", "Finger extension splint only"], correctIndex: 1, rationale: "Radial nerve palsy: wrist drop (loss of wrist/finger/thumb extension). Wrist cock-up splint maintains wrist in functional extension, allowing finger flexors to function for grip. Dynamic splint assists active extension during nerve recovery.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "Splinting" },
  { id: "ota-2163", stem: "An OTA is educating a client with osteoporosis about safe body mechanics. Which instruction is MOST important?", options: ["Bend at the waist to lift", "Avoid spinal flexion and twisting; use hip hinge technique for lifting; and maintain upright posture to reduce vertebral compression fracture risk", "Lift heavy objects overhead", "Perform sit-ups for core strength"], correctIndex: 1, rationale: "Osteoporosis body mechanics: avoid spinal flexion (increases anterior vertebral compression), avoid combined flexion/rotation, hip hinge for lifting, maintain extension posture, and use assistive devices for heavy tasks.", difficulty: 1, category: "Geriatric Rehabilitation", topic: "Geriatric OT" },
  { id: "ota-2164", stem: "A client with sensory processing disorder demonstrates sensory seeking behavior. Which intervention is appropriate?", options: ["Restrict all movement", "Provide structured sensory diet with regular opportunities for heavy work, proprioceptive input, and movement throughout the day", "Ignore the behavior", "Only calming activities"], correctIndex: 1, rationale: "Sensory seeking: child needs more sensory input to regulate. Sensory diet with scheduled heavy work (carrying, pushing, climbing), proprioceptive activities, movement breaks, and organized sensory opportunities throughout the day.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "Sensory Processing" },
  { id: "ota-2165", stem: "An OTA is treating a client with frozen shoulder (adhesive capsulitis) in the 'frozen' stage. What is the primary treatment goal?", options: ["Aggressive stretching", "Maintain available ROM with gentle stretching within pain tolerance while managing pain and preserving function", "Forceful manipulation", "No treatment until thawing stage"], correctIndex: 1, rationale: "Adhesive capsulitis frozen stage: maintain available ROM with gentle stretching (within pain limits), pain management, joint mobilization (within tolerance), functional activity modification, and patient education about the natural history.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-2166", stem: "A client with a cognitive deficit is unable to recognize familiar objects by sight. This condition is called:", options: ["Aphasia", "Visual agnosia — inability to recognize objects through vision despite intact visual acuity", "Apraxia", "Neglect"], correctIndex: 1, rationale: "Visual agnosia: inability to recognize objects by sight despite intact visual acuity. The client can describe features but cannot identify the object. May recognize through touch or sound. Different from anomia (word-finding difficulty).", difficulty: 3, category: "Neurological Rehabilitation", topic: "Cognitive Rehab" },
  { id: "ota-2167", stem: "An OTA is providing wheelchair seating assessment. What measurement determines seat width?", options: ["Shoulder width only", "Widest point across the hips/thighs plus 1-2 inches for clearance and clothing", "Waist circumference", "Arm length"], correctIndex: 1, rationale: "Wheelchair seat width: measure widest point across hips/thighs while seated, add 1-2 inches (each side) for clearance and clothing. Too narrow: pressure on trochanters. Too wide: difficulty reaching rims, poor posture, wider turning radius.", difficulty: 1, category: "Assistive Devices", topic: "Assistive Devices" },
  { id: "ota-2168", stem: "A client with HIV/AIDS is being treated in an outpatient OT clinic. What standard precaution is essential?", options: ["Wear a respirator mask at all times", "Use standard (universal) precautions with all clients — treat all blood and body fluids as potentially infectious", "Double gloving is always required", "Isolate the client from others"], correctIndex: 1, rationale: "Standard precautions apply to ALL clients regardless of diagnosis: hand hygiene, PPE when contact with blood/body fluids expected, sharps disposal, and surface disinfection. No special precautions beyond standard are needed for HIV.", difficulty: 1, category: "Patient Safety", topic: "Rehabilitation Principles" },
  { id: "ota-2169", stem: "An OTA is treating a client with an incomplete SCI who demonstrates sacral sparing. What is the clinical significance?", options: ["No significance", "Sacral sparing indicates an incomplete injury with potential for further neurological recovery below the injury level", "The injury is complete", "Only affects bowel function"], correctIndex: 1, rationale: "Sacral sparing: preservation of sensation at S4-S5 dermatomes, voluntary anal contraction, or deep anal pressure. Indicates incomplete SCI (ASIA B-D). Incomplete injuries have better prognosis for neurological recovery than complete injuries.", difficulty: 4, category: "Neurological Rehabilitation", topic: "Neurological Rehab" },
  { id: "ota-2170", stem: "A client is being discharged home with a continuous passive motion (CPM) machine after total knee replacement. What education should the OTA provide?", options: ["Use CPM at maximum speed", "Follow prescribed ROM settings, use for prescribed duration, monitor skin integrity, and report increased pain or swelling", "Only use when someone else is present", "CPM replaces all other exercise"], correctIndex: 1, rationale: "CPM education: follow surgeon's ROM parameters, use for prescribed duration (often 6-8 hours/day), monitor skin under straps, proper limb positioning, stop if increased pain/swelling, and CPM supplements — not replaces — active exercise.", difficulty: 2, category: "Patient Education", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-2171", stem: "An OTA is treating a child with Down syndrome. Which musculoskeletal concern requires monitoring?", options: ["Hypertonia", "Atlantoaxial instability — cervical spine instability between C1-C2 that contraindicates certain physical activities", "Increased bone density", "Joint stiffness"], correctIndex: 1, rationale: "Down syndrome atlantoaxial instability (C1-C2): approximately 15% have radiographic instability. Avoid activities that stress the neck (somersaults, heading soccer balls, diving). Hypotonia and joint hypermobility also require attention.", difficulty: 3, category: "Pediatric Rehabilitation", topic: "Pediatric OT" },
  { id: "ota-2172", stem: "A client with a below-elbow amputation is learning myoelectric prosthesis control. What muscles are typically used for signal input?", options: ["Shoulder muscles", "Wrist extensors and wrist flexors of the residual forearm to control hand open and close functions", "Biceps only", "Chest muscles"], correctIndex: 1, rationale: "Below-elbow myoelectric prosthesis: electrodes placed over wrist extensors (open hand) and wrist flexors (close hand). Two-site, two-function control. Client must learn to produce consistent, isolated muscle contractions.", difficulty: 3, category: "Clinical Case Scenarios", topic: "Assistive Devices" },
  { id: "ota-2173", stem: "An OTA is working with a client who has fibromyalgia. Which exercise approach is evidence-based?", options: ["High-intensity resistance training", "Low to moderate intensity aerobic exercise, gentle stretching, and aquatic therapy with gradual progression", "No exercise is recommended", "Only passive modalities"], correctIndex: 1, rationale: "Fibromyalgia exercise: low-moderate intensity aerobic exercise (walking, swimming, cycling), gentle stretching, aquatic therapy (warm water reduces pain, supports joints), gradual progression, and avoiding overexertion that triggers flares.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "Rehabilitation Principles" },
  { id: "ota-2174", stem: "A client with hemianopsia is having difficulty reading. Which compensatory technique should the OTA teach?", options: ["Use smaller font", "Turn the reading material so text runs vertically into the intact visual field, use a line guide, and practice systematic scanning into the blind field", "Cover one eye", "Read only with audiobooks"], correctIndex: 1, rationale: "Hemianopsia reading compensations: turn text vertically (top-to-bottom reading), typoscope/line guide to maintain place, large print, systematic scanning into blind field, and head turning toward the affected side.", difficulty: 3, category: "Neurological Rehabilitation", topic: "Cognitive Rehab" },
  { id: "ota-2175", stem: "An OTA is assessing a client's sensation using Semmes-Weinstein monofilaments. What does this assessment measure?", options: ["Two-point discrimination", "Light touch-deep pressure threshold — the minimum force detected by the skin, mapped to functional sensory capacity", "Temperature sensation", "Vibration sense"], correctIndex: 1, rationale: "Semmes-Weinstein monofilaments: calibrated nylon filaments of increasing diameter/force. Tests light touch-deep pressure threshold. Maps functional sensation: green (normal), blue (diminished light touch), purple (diminished protective), red (loss of protective), untestable.", difficulty: 2, category: "Clinical Scenarios", topic: "Hand Therapy" },
  { id: "ota-2176", stem: "A client with early-stage amyotrophic lateral sclerosis (ALS) is referred to OT. What is the PRIMARY focus of intervention?", options: ["Strengthening exercises to reverse weakness", "Maintaining current function, energy conservation education, adaptive equipment training, and proactive planning for progressive decline", "Only emotional support", "Discharge from OT services"], correctIndex: 1, rationale: "Early ALS OT: maintain current function, energy conservation, adaptive equipment as needed, home modification planning, AT assessment (voice banking, writing alternatives), caregiver education, and advance care planning.", difficulty: 2, category: "Neurological Rehabilitation", topic: "Neurological Rehab" },
  { id: "ota-2177", stem: "An OTA is using the Model of Human Occupation (MOHO) framework. Which component addresses a client's roles and habits?", options: ["Performance capacity", "Habituation — the process by which occupation is organized into patterns through roles, habits, and routines", "Volition", "Environment"], correctIndex: 1, rationale: "MOHO Habituation: internalized readiness to exhibit patterns of behavior through habits (automatic behavior patterns) and roles (socially defined positions with expectations). Organizes daily occupation into predictable patterns.", difficulty: 3, category: "Rehabilitation Planning", topic: "Rehabilitation Principles" },
  { id: "ota-2178", stem: "A client with a total shoulder replacement has which movement restriction in the early postoperative phase?", options: ["No restrictions", "Avoid active external rotation and extension beyond neutral to protect the subscapularis repair", "Avoid all movement for 12 weeks", "Only avoid overhead reaching"], correctIndex: 1, rationale: "Total shoulder arthroplasty precautions: protect subscapularis repair by limiting active ER and extension behind neutral for 6 weeks. Passive and AAROM in protected ranges per surgeon protocol. Sling for 4-6 weeks.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-2179", stem: "An OTA is treating a client with tardive dyskinesia from long-term antipsychotic use. Which symptoms are characteristic?", options: ["Tremor at rest", "Involuntary repetitive movements of the face, tongue, and extremities including lip smacking, tongue protrusion, and choreiform movements", "Rigidity only", "Postural instability only"], correctIndex: 1, rationale: "Tardive dyskinesia: involuntary, repetitive movements — orofacial (lip smacking, tongue protrusion, jaw movements), trunk, and extremities (choreiform movements). Caused by long-term dopamine-blocking antipsychotics. May be irreversible.", difficulty: 3, category: "Neurological Rehabilitation", topic: "Mental Health OT" },
  { id: "ota-2180", stem: "A client with bilateral hand osteoarthritis has difficulty opening jars. Which joint protection strategy should the OTA teach?", options: ["Use stronger grip force", "Use built-up handles, jar openers, leverage-based tools, and avoid sustained tight gripping to reduce joint stress", "Open jars with teeth", "Only use canned goods"], correctIndex: 1, rationale: "OA joint protection for jars: use rubber grip aids, electric jar openers, jar opener mounted under cabinet, built-up handles on tools, and use larger joints/leverage instead of small joint force. Avoid sustained tight gripping.", difficulty: 1, category: "Geriatric Rehabilitation", topic: "Assistive Devices" },
  { id: "ota-2181", stem: "An OTA is providing intervention for a child with handwriting difficulties due to poor visual-motor integration. Which preparatory activity is appropriate?", options: ["Tracing over letters repeatedly", "Copying shapes of increasing complexity, mazes, dot-to-dot activities, and constructional tasks to build visual-motor skills before letter formation", "Only verbal instruction on letter formation", "Typing instead of handwriting"], correctIndex: 1, rationale: "Visual-motor integration preparatory activities: copying shapes (progressing in complexity), mazes, dot-to-dot, bead stringing, cutting, building with blocks, and drawing before letter formation. Builds the visual-motor foundation for handwriting.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "Pediatric OT" },
  { id: "ota-2182", stem: "A client with bilateral lower extremity amputations needs a wheelchair with what modification?", options: ["Standard wheelchair", "Rear axle set further back (amputee wheelchair) to compensate for the posterior shift in center of gravity and prevent tipping backward", "Wider front wheels", "Higher seat height"], correctIndex: 1, rationale: "Bilateral LE amputee wheelchair: rear axle set back 2-3 inches to compensate for the posterior shift in center of gravity (loss of leg weight anteriorly). Prevents backward tipping. May also add anti-tip casters.", difficulty: 3, category: "Assistive Devices", topic: "Assistive Devices" },
  { id: "ota-2183", stem: "An OTA is teaching a client with hemiplegia to use a rocker knife. What is the advantage of this utensil?", options: ["It's heavier for stability", "It allows one-handed cutting by using a rocking motion instead of the sawing motion that requires bilateral hand coordination", "It's sharper than standard knives", "It doubles as a fork"], correctIndex: 1, rationale: "Rocker knife: curved blade allows one-handed cutting with a rocking motion. Eliminates need for bilateral coordination (holding fork in one hand, knife in other). Available with built-up handles for weak grip.", difficulty: 1, category: "Assistive Devices", topic: "ADL Training" },
  { id: "ota-2184", stem: "A client with a flexor tendon laceration in Zone I (profundus only) cannot flex which joint?", options: ["MCP joint", "DIP joint — Zone I involves only the FDP tendon insertion, resulting in inability to actively flex the distal interphalangeal joint", "PIP joint", "Wrist joint"], correctIndex: 1, rationale: "Zone I flexor tendon: only FDP present (FDS inserts at Zone II). FDP laceration in Zone I causes inability to actively flex DIP while PIP and MCP flexion remain intact (FDS and intrinsics preserved).", difficulty: 4, category: "Anatomy & Physiology", topic: "Hand Therapy" },
  { id: "ota-2185", stem: "An OTA is working with a client who hoards objects. Which theoretical framework guides intervention?", options: ["Only behavioral modification", "Cognitive-behavioral therapy addressing distorted beliefs about possessions, emotional attachment, decision-making deficits, and avoidance behaviors", "Only family counseling", "Only medication management"], correctIndex: 1, rationale: "Hoarding disorder CBT: address distorted beliefs about possessions (usefulness, attachment, responsibility), improve decision-making skills, reduce avoidance of discarding, organize belongings, and create functional living spaces.", difficulty: 3, category: "Clinical Case Scenarios", topic: "Mental Health OT" },
  { id: "ota-2186", stem: "A client with a new tracheostomy is participating in OT. What safety consideration is essential?", options: ["Cover the tracheostomy during activities", "Monitor respiratory status, ensure suctioning equipment is nearby, avoid water near the stoma, and know emergency procedures for decannulation", "Remove the tracheostomy during therapy", "No special considerations"], correctIndex: 1, rationale: "Tracheostomy safety during OT: monitor respiratory status, suction equipment accessible, protect stoma from water/debris, secure trach ties, know emergency protocols, humidity for secretion management, and coordinate with respiratory therapy.", difficulty: 2, category: "Patient Safety", topic: "Rehabilitation Principles" },
  { id: "ota-2187", stem: "An OTA is treating a client with a distal radius fracture that has healed. At 8 weeks post-injury, what treatment is appropriate?", options: ["Only passive ROM", "Progressive strengthening, functional activities, scar management if applicable, and restoration of grip and pinch strength", "Return to full activity without restrictions", "Continue immobilization"], correctIndex: 1, rationale: "Distal radius fracture at 8 weeks (healed): progressive strengthening (grip, pinch, wrist), functional activities, scar management, joint mobilization if stiff, desensitization if needed, and ergonomic education for return to activity.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-2188", stem: "A client using a power wheelchair has limited hand function. Which drive control is MOST appropriate?", options: ["Standard joystick", "Proportional head-array control, chin control, or sip-and-puff system based on the client's available motor function", "Foot pedals", "Manual propulsion"], correctIndex: 1, rationale: "Power wheelchair alternative controls: head array, chin control, sip-and-puff, eye gaze, switch scanning, or proportional controls. Selection based on available motor function, cognition, and environment. OTA trains control use.", difficulty: 3, category: "Assistive Devices", topic: "Assistive Devices" },
  { id: "ota-2189", stem: "An OTA is providing community reintegration for a client with a brain injury. Which IADL should be assessed first?", options: ["Gardening", "Money management, medication management, and community mobility as they are essential for safe independent living", "Leisure activities", "Social media use"], correctIndex: 1, rationale: "Community reintegration IADL priority: safety-critical IADLs first — money management, medication management, and community mobility (transportation). These are essential for safe, independent community living.", difficulty: 1, category: "Rehabilitation Planning", topic: "ADL Training" },
  { id: "ota-2190", stem: "A client with a cervical fusion at C5-C6 has movement restrictions. Which activity is contraindicated?", options: ["Gentle shoulder rolls", "Rapid cervical rotation, extreme flexion/extension, and high-impact activities that could stress the fusion site", "Walking", "Eating independently"], correctIndex: 1, rationale: "Cervical fusion precautions: avoid rapid/extreme cervical motion (flexion, extension, rotation), high-impact activities, heavy lifting, and activities that jar the cervical spine. Follow surgeon's specific activity restrictions.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-2191", stem: "An OTA is treating a client with generalized anxiety disorder. Which occupation-based intervention is therapeutic?", options: ["Only discuss worries", "Mindfulness-based activities, graded exposure to anxiety-provoking situations through daily occupations, and relaxation techniques embedded in functional tasks", "Avoid all anxiety-provoking situations", "Only refer to psychiatry"], correctIndex: 1, rationale: "GAD OT intervention: mindfulness during ADLs, graded exposure through daily occupations, relaxation techniques (PMR, deep breathing, guided imagery), routine establishment, time management, and building self-efficacy in functional tasks.", difficulty: 2, category: "Clinical Case Scenarios", topic: "Mental Health OT" },
  { id: "ota-2192", stem: "A client with a boutonniere deformity has which finger position?", options: ["PIP hyperextension, DIP flexion", "PIP flexion and DIP hyperextension due to central slip disruption and lateral band displacement volar to the PIP axis", "MCP hyperextension", "All joints in flexion"], correctIndex: 1, rationale: "Boutonniere deformity: PIP flexion + DIP hyperextension. Caused by central slip rupture at PIP, lateral bands migrate volar to PIP axis (flex PIP) and concentrate extension force at DIP (hyperextend DIP). Opposite of swan neck.", difficulty: 4, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2193", stem: "An OTA is planning a fall prevention program for older adults. Which component is MOST essential?", options: ["Only installing grab bars", "Multifactorial assessment including balance exercises, home hazard modification, medication review, vision screening, and education about risk factors", "Only exercise classes", "Only providing walkers"], correctIndex: 1, rationale: "Fall prevention program: multifactorial — balance/strength exercises, home hazard assessment/modification, medication review, vision correction, footwear education, assistive device assessment, and education about fall risk factors.", difficulty: 1, category: "Geriatric Rehabilitation", topic: "Geriatric OT" },
  { id: "ota-2194", stem: "A client with schizophrenia demonstrates flat affect and social withdrawal. Which OT group level is appropriate initially?", options: ["Cooperative group", "Parallel group — performing individual tasks in the presence of others with minimal interaction required", "Mature group", "Project group"], correctIndex: 1, rationale: "Mosey's group interaction skill levels for schizophrenia with negative symptoms: start with parallel group (individual tasks, minimal social demand, presence of others). Progress through project → egocentric-cooperative → cooperative → mature.", difficulty: 2, category: "Clinical Case Scenarios", topic: "Mental Health OT" },
  { id: "ota-2195", stem: "An OTA is evaluating a client for wheelchair cushion selection. A client with a spinal cord injury is at high risk for pressure injuries. Which cushion type provides the BEST pressure distribution?", options: ["Standard foam cushion", "Alternating pressure or custom-molded cushion that maximizes contact area and distributes pressure evenly across the seating surface", "No cushion needed", "Donut-shaped cushion"], correctIndex: 1, rationale: "High-risk SCI cushion selection: custom-molded or high-end alternating pressure cushions maximize contact area and distribute pressure. Gel, air (ROHO), or hybrid cushions also used. Donut cushions are contraindicated (increase pressure at edges).", difficulty: 3, category: "Assistive Devices", topic: "Assistive Devices" },
  { id: "ota-2196", stem: "A client with a healed Colles' fracture has limited forearm supination. Which activity promotes supination?", options: ["Typing on a keyboard", "Turning a doorknob, using a screwdriver, or turning pages of a book — activities that require forearm rotation into supination", "Lifting weights overhead", "Squeezing a stress ball"], correctIndex: 1, rationale: "Forearm supination functional activities: turning doorknobs, using screwdriver, turning pages, eating with a spoon (bringing to mouth), accepting change (palm up), and therapeutic exercise with supination against resistance.", difficulty: 1, category: "Orthopedic Rehabilitation", topic: "Musculoskeletal Rehabilitation" },
  { id: "ota-2197", stem: "An OTA is conducting a home evaluation for a client using a wheelchair. What is the minimum doorway width for wheelchair access?", options: ["24 inches", "32 inches minimum, with 36 inches preferred for comfortable wheelchair passage per ADA guidelines", "48 inches", "18 inches"], correctIndex: 1, rationale: "Wheelchair doorway access: 32-inch minimum clear opening (ADA), 36 inches preferred. Standard doors are 30-36 inches but frame reduces clearance. May need offset hinges, wider doors, or doorway widening for adequate access.", difficulty: 1, category: "Assistive Devices", topic: "Assistive Devices" },
  { id: "ota-2198", stem: "A client with a recent stroke has flaccid upper extremity. What positioning is essential to prevent shoulder subluxation?", options: ["Let the arm hang freely", "Support the arm with a lap tray, arm trough, or sling to maintain glenohumeral alignment and prevent inferior subluxation", "Elevate the arm overhead", "Strap the arm to the body"], correctIndex: 1, rationale: "Flaccid shoulder post-stroke: support arm with lap tray (seated), arm trough on wheelchair, sling during ambulation, proper positioning in bed (pillow support). Prevent inferior subluxation from gravitational pull on unsupported arm.", difficulty: 1, category: "Neurological Rehabilitation", topic: "Neurological Rehab" },
  { id: "ota-2199", stem: "An OTA is providing driver rehabilitation screening. Which client condition is an absolute contraindication for driving?", options: ["Mild arthritis", "Active uncontrolled seizure disorder with loss of consciousness that does not meet the state's seizure-free driving requirement", "Wearing eyeglasses", "Mild hearing loss"], correctIndex: 1, rationale: "Driving contraindications: uncontrolled seizures (most states require seizure-free period of 3-12 months), severe visual impairment below state requirements, active substance abuse, and severe cognitive deficits affecting safety judgment.", difficulty: 2, category: "Rehabilitation Planning", topic: "ADL Training" },
  { id: "ota-2200", stem: "A client with a flexor tendon repair is 4 weeks post-surgery. The OTA notices the tendon is not gliding well. Which exercise promotes differential tendon gliding?", options: ["Static splinting only", "Place-and-hold exercises and isolated FDS/FDP exercises (hook fist, straight fist, full fist) to promote differential gliding between tendons", "Aggressive passive stretching", "Resistive grip exercises"], correctIndex: 1, rationale: "Differential tendon gliding exercises: hook fist (FDP, DIP/PIP flexion, MCP extension), straight fist (FDS, PIP/MCP flexion, DIP extension), full fist (both). Place-and-hold at 4 weeks promotes active tendon excursion safely.", difficulty: 4, category: "Orthopedic Rehabilitation", topic: "Hand Therapy" },
  { id: "ota-2201", stem: "An OTA is treating a client with anorexia nervosa in a day treatment program. Which OT intervention is appropriate?", options: ["Only meal supervision", "Body image activities, healthy coping skills development, meaningful occupation exploration, and building self-esteem through mastery experiences", "Only cooking groups", "Avoid discussing food entirely"], correctIndex: 1, rationale: "Anorexia OT: body image work (art, movement, mirror activities), healthy coping skill development, meaningful occupation exploration, self-esteem building through mastery, social skills, stress management, and meal-related activities when appropriate.", difficulty: 2, category: "Clinical Case Scenarios", topic: "Mental Health OT" },
  { id: "ota-2202", stem: "A client with peripheral neuropathy has decreased proprioception in the feet. Which fall prevention strategy is MOST important for ADL safety?", options: ["Walk faster", "Use adequate lighting, visual compensation for proprioceptive loss, supportive footwear, and clear pathways to prevent falls", "Walk barefoot for sensory input", "Only use a wheelchair"], correctIndex: 1, rationale: "Peripheral neuropathy fall prevention: visual compensation (adequate lighting, watch foot placement), supportive enclosed footwear (avoid barefoot/slippers), clear pathways, nightlights, assistive device if needed, and balance training.", difficulty: 2, category: "Geriatric Rehabilitation", topic: "Rehabilitation Principles" },
];
